// ── Helper functions ────────────────────────────────────────────

func stateLabel(state string) string {
	switch state {
	case StateOpen:
		return "Open"
	case StateActive:
		return "Active"
	case StateReview:
		return "Review"
	case StateDone:
		return "Done"
	case StateClosed:
		return "Closed"
	default:
		return state
	}
}

func stateBgClass(state string) string {
	switch state {
	case StateOpen:
		return "bg-warm-faint/20 text-warm-muted"
	case StateActive:
		return "bg-indigo-500/15 text-indigo-400"
	case StateReview:
		return "bg-amber-500/15 text-amber-400"
	case StateDone:
		return "bg-emerald-500/15 text-emerald-400"
	case StateClosed:
		return "bg-warm-faint/20 text-warm-faint"
	default:
		return "bg-warm-faint/20 text-warm-muted"
	}
}

func stateColorHex(state string) string {
	switch state {
	case StateOpen:
		return "var(--color-warm-muted)"
	case StateActive:
		return "var(--color-state-active)"
	case StateReview:
		return "var(--color-state-review)"
	case StateDone:
		return "var(--color-state-done)"
	case StateClosed:
		return "var(--color-warm-faint)"
	default:
		return "var(--color-warm-muted)"
	}
}

func priorityDotHex(priority string) string {
	switch priority {
	case PriorityUrgent:
		return "var(--color-priority-urgent)"
	case PriorityHigh:
		// Intentional reuse: high priority shares the review amber.
		return "var(--color-state-review)"
	case PriorityMedium:
		return "var(--color-brand)"
	case PriorityLow:
		return "var(--color-warm-muted)"
	default:
		return "var(--color-warm-muted)"
	}
}

func boardEmpty(columns []BoardColumn) bool {
	for _, col := range columns {
		if len(col.Nodes) > 0 {
			return false
		}
	}
	return true
}

func dashboardStateClass(state string) string {
	switch state {
	case StateOpen:
		return "bg-warm-faint/20 text-warm-muted"
	case StateActive:
		return "bg-indigo-500/15 text-indigo-400"
	case StateReview:
		return "bg-amber-500/15 text-amber-400"
	default:
		return "bg-warm-faint/20 text-warm-muted"
	}
}

func dashRelativeTime(t time.Time) string {
	d := time.Since(t)
	switch {
	case d < time.Minute:
		return "now"
	case d < time.Hour:
		return fmt.Sprintf("%dm", int(d.Minutes()))
	case d < 24*time.Hour:
		return fmt.Sprintf("%dh", int(d.Hours()))
	case d < 30*24*time.Hour:
		return fmt.Sprintf("%dd", int(d.Hours()/24))
	default:
		return t.Format("Jan 2")
	}
}

func truncateBody(s string, maxLen int) string {
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen] + "..."
}

func kindBadgeClass(kind string) string {
	switch kind {
	case KindTask, SpaceProject:
		return "bg-indigo-500/15 text-indigo-400"
	case KindPost, SpaceCommunity:
		return "bg-emerald-500/15 text-emerald-400"
	case KindThread, SpaceTeam:
		return "bg-amber-500/15 text-amber-400"
	case KindComment:
		return "bg-warm-faint/20 text-warm-muted"
	default:
		return "bg-warm-faint/20 text-warm-muted"
	}
}

func opBadgeClass(op string) string {
	switch op {
	case "intend", "decompose":
		return "bg-indigo-500/15 text-indigo-400"
	case "express", "discuss":
		return "bg-emerald-500/15 text-emerald-400"
	case "respond":
		return "bg-warm-faint/20 text-warm-muted"
	case "complete":
		return "bg-emerald-500/15 text-emerald-400"
	case "claim", "assign":
		return "bg-amber-500/15 text-amber-400"
	case "prioritize":
		return "bg-purple-500/15 text-purple-400"
	case "review":
		return "bg-amber-500/15 text-amber-400"
	case "progress":
		return "bg-blue-500/15 text-blue-400"
	default:
		return "bg-warm-faint/20 text-warm-muted"
	}
}

func renderMarkdown(src string) templ.Component {
	var buf bytes.Buffer
	md := goldmark.New()
	if err := md.Convert([]byte(src), &buf); err != nil {
		return templ.Raw("<p>" + src + "</p>")
	}
	return templ.Raw(buf.String())
}

func resolveName(id string, nameMap map[string]string) string {
	if nameMap != nil {
		if name, ok := nameMap[id]; ok {
			return name
		}
	}
	return id
}

func initial(name string) string {
	runes := []rune(name)
	if len(runes) == 0 {
		return "?"
	}
	return string(runes[0:1])
}

func childProgress(node Node) string {
	if node.ChildCount == 0 {
		return "width: 0%"
	}
	pct := (node.ChildDone * 100) / node.ChildCount
	return fmt.Sprintf("width: %d%%", pct)
}

func childProgressSlice(nodes []Node) string {
	if len(nodes) == 0 {
		return "width: 0%"
	}
	done := countDone(nodes)
	pct := (done * 100) / len(nodes)
	return fmt.Sprintf("width: %d%%", pct)
}

func countDone(nodes []Node) int {
	n := 0
	for _, nd := range nodes {
		if nd.State == StateDone {
			n++
		}
	}
	return n
}

func truncate(s string, max int) string {
	if len(s) <= max {
		return s
	}
	return s[:max] + "…"
}

func quotePostPlaceholder(q *Node) string {
	if q != nil {
		return "Add your thoughts..."
	}
	return "What's on your mind?"
}

func personaOnlineStatus(p *AgentPersona) string {
	if p == nil || p.LastSeen == nil {
		return ""
	}
	d := time.Since(*p.LastSeen)
	if d < 5*time.Minute {
		return "Online"
	}
	if d < 60*time.Minute {
		return fmt.Sprintf("%dm ago", int(d.Minutes()))
	}
	if d < 24*time.Hour {
		return fmt.Sprintf("%dh ago", int(d.Hours()))
	}
	return fmt.Sprintf("%dd ago", int(d.Hours()/24))
}

func containsStr(ss []string, s string) bool {
	for _, v := range ss {
		if v == s {
			return true
		}
	}
	return false
}

func lastMessageTS(messages []Node) string {
	if len(messages) == 0 {
		return time.Now().UTC().Format(time.RFC3339Nano)
	}
	return messages[len(messages)-1].CreatedAt.Format(time.RFC3339Nano)
}

func lensTooltip(lens string) string {
	switch lens {
	case "board":
		return "Track and prioritize tasks by status"
	case "conversations":
		return "Direct conversations with teammates and agents"
	case "feed":
		return "Activity stream of posts and updates"
	case "people":
		return "Team members, agents, and collaborators"
	case "threads":
		return "Topic discussions and ongoing conversations"
	case "council":
		return "Convene multiple agents on a single question"
	case "knowledge":
		return "Assert what you know, challenge what you doubt"
	case "governance":
		return "Propose changes and vote on decisions"
	case "changelog":
		return "Completed tasks — what shipped and when"
	default:
		return ""
	}
}

// ── Knowledge lens (Layer 6) ────────────────────────────────────

func knowledgeTabURL(slug, tab, q string) string {
	u := "/app/" + slug + "/knowledge?tab=" + tab
	if q != "" {
		u += "&q=" + url.QueryEscape(q)
	}
	return u
}

